import socket
# Check gateway and key IPs quickly
targets = ['10.240.128.1', '10.240.128.2', '10.240.128.254', '127.0.0.1']
ports = [22, 80, 443, 8080, 3000]
for host in targets:
    for port in ports:
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(0.5)
            r = s.connect_ex((host, port))
            s.close()
            if r == 0:
                print(f'OPEN: {host}:{port}')
            elif r == 111:
                print(f'REFUSED(up): {host}:{port}')
        except Exception as e:
            pass
print('done')
